const { Manifold, CrossSection, label, setCircularSegments } = api;
setCircularSegments(48);

// Helper: box from min..max
function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// --- Stem: tapered cylinder, slightly wider at base ---
// r_base=4.5, r_top=3.5, h=15, from z=1.5 to z=16.5
const stem = label(Manifold.cylinder(15, 4.5, 3.5, 48).translate([0, 0, 1.5]), 'stem');

// --- Collar ring: thin solid disk around stem at z=14 ---
// Make it a full disk (no subtraction) that overlaps the stem
const collar = label(Manifold.cylinder(1.5, 5.5, 5.5, 48).translate([0, 0, 14]), 'collar');

// --- Cap: squashed sphere dome ---
// Center at z=18, scale 0.75 in Z, r=12
// The sphere extends from z=18-9=9 to z=18+9=27 in Z (scaled 0.75)
// Cut below z=15 - the cap brim overlaps the stem top (z=16.5) by starting at z=15
// Actually cut at z=15 keeps cap from z=15..27, which overlaps stem z=1.5..16.5 by 1.5 units
const capSphere = Manifold.sphere(12, 48).scale([1, 1, 0.75]).translate([0, 0, 18]);
const capCut = box([-15, -15, -10], [15, 15, 15]);
const cap = label(capSphere.subtract(capCut), 'cap');

// --- Grass base: flat green disk ---
const grass = label(Manifold.cylinder(2, 8, 8.5, 48).translate([0, 0, 0]), 'grass');

// Assemble
return grass
  .add(stem)
  .add(collar)
  .add(cap);
